import React, { useEffect } from "react";
import useSplitPaymentStore from "../useSplitPaymentStore";
import useData, { getInstallments } from "../useData";

export function PlanScheduleItem({ item }) {
    if (item) {
        const { dueDateLabel, dueAmt } = item
        return (<div className="m-2 bg-sky-50 p-4 w-2/3 grid gap-4 grid-cols-2 margin-auto">
            <div className="w-50">{'Rs.' + dueAmt}</div>
            <div className="w-50">{dueDateLabel}</div>
        </div>)
    }
}

function PlanSchedule() {
    const { totalAmount, activePlan } = useSplitPaymentStore((s) => s)
    const { data: plansSchedule, loading, error, refetch } = useData(null, {
        loadOnRefetch: true
    })
    useEffect(() => {
        if (totalAmount && activePlan) {
            refetch(() => getInstallments(totalAmount, activePlan))
        }
    }, [totalAmount, activePlan])

    console.log('USE DATA', error?.log)

    if (loading) {
        return <div>Loading...</div>
    }

    if (error) {
        return <div>{error.message}</div>
    }

    if (plansSchedule && plansSchedule.length > 0) {
        return (
            <div className="flex flex-col justify-between items-center">
                {plansSchedule.map((item) => {
                    return (<PlanScheduleItem key={item.id} item={item} />)
                })}
            </div>
        )
    }
    return null
}

export default PlanSchedule
